            if (parity1 === targetParity) {
                continue; // Achievable with nums1[i]
            }

            // Case 2: nums2[i] = nums1[i] - nums1[j], where j != i and nums1[i] - nums1[j] >= 1
            let achievableBySubtraction = false;
            for (let j = 0; j < n; j++) {
                if (i === j) continue;

                const diff = nums1[i] - nums1[j];
                if (diff >= 1) {
                    // Parity of (A - B) is the same as the parity of (A + B)
                    // (nums1[i] - nums1[j]) % 2 == (nums1[i] + nums1[j]) % 2
                    const parity2 = diff % 2;
                    if (parity2 === targetParity) {
                        achievableBySubtraction = true;
                        break;
                    }
                }
            }

            if (!achievableBySubtraction) {
                return false; // Cannot achieve the target parity for nums2[i]
            }
        }
        return true; // All elements can achieve the target parity
    };

    // Check if an all-odd array (targetParity = 1) can be constructed
    if (canAchieveParity(1)) {
        return true;
    }

    // Check if an all-even array (targetParity = 0) can be constructed
    if (canAchieveParity(0)) {
        return true;
    }

    return false;
}
